import numpy as np

def ndcg_at_k(ranked_docs: list[str], relevant_docs: set[str], k: int = 5) -> float:
    """Compute nDCG@k. relevant_docs is a set of document IDs considered relevant."""
    def dcg(docs, k):
        gains = [1.0 / np.log2(i + 2) for i, d in enumerate(docs[:k]) if d in relevant_docs]
        return sum(gains)

    ideal_hits = min(len(relevant_docs), k)
    ideal = sum(1.0 / np.log2(i + 2) for i in range(ideal_hits))
    return dcg(ranked_docs, k) / ideal if ideal > 0 else 0.0

def mrr(ranked_docs: list[str], relevant_docs: set[str]) -> float:
    """Mean Reciprocal Rank for a single query."""
    for rank, doc_id in enumerate(ranked_docs, start=1):
        if doc_id in relevant_docs:
            return 1.0 / rank
    return 0.0

# Example evaluation
before_rerank = ["doc_3", "doc_7", "doc_1", "doc_2", "doc_5"]  # original retrieval order
after_rerank  = ["doc_1", "doc_3", "doc_5", "doc_7", "doc_2"]  # after cross-encoder
ground_truth  = {"doc_1", "doc_5"}

print(f"nDCG@5 before: {ndcg_at_k(before_rerank, ground_truth):.3f}")
print(f"nDCG@5 after:  {ndcg_at_k(after_rerank,  ground_truth):.3f}")
print(f"MRR before:    {mrr(before_rerank, ground_truth):.3f}")
print(f"MRR after:     {mrr(after_rerank,  ground_truth):.3f}")
